### E2E Test Script: tests/e2e/robot_mode_test.sh

```bash
#!/bin/bash
# Robot Mode E2E Test Suite
# Comprehensive tests for dcg --robot mode
#
# Usage:
#   ./tests/e2e/robot_mode_test.sh
#   DCG_BINARY=/path/to/dcg ./tests/e2e/robot_mode_test.sh
#
# Exit codes:
#   0 - All tests passed
#   1 - Test failure
#   2 - Setup/infrastructure error

set -euo pipefail

#------------------------------------------------------------------------------
# Configuration
#------------------------------------------------------------------------------

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
DCG="${DCG_BINARY:-$PROJECT_ROOT/target/release/dcg}"
LOG_FILE="${LOG_FILE:-/tmp/robot_mode_test.log}"

# Colors (disabled if NO_COLOR is set)
if [ -z "${NO_COLOR:-}" ]; then
    RED='\033[0;31m'
    GREEN='\033[0;32m'
    YELLOW='\033[0;33m'
    NC='\033[0m' # No Color
else
    RED=''
    GREEN=''
    YELLOW=''
    NC=''
fi

#------------------------------------------------------------------------------
# Logging
#------------------------------------------------------------------------------

TESTS_RUN=0
TESTS_PASSED=0
TESTS_FAILED=0

log() {
    local msg="[$(date '+%Y-%m-%d %H:%M:%S')] $*"
    echo "$msg" >> "$LOG_FILE"
    echo "$msg" >&2
}

log_pass() {
    log "${GREEN}PASS${NC}: $1"
    ((TESTS_PASSED++))
}

log_fail() {
    log "${RED}FAIL${NC}: $1"
    ((TESTS_FAILED++))
}

log_warn() {
    log "${YELLOW}WARN${NC}: $1"
}

#------------------------------------------------------------------------------
# Setup
#------------------------------------------------------------------------------

setup() {
    log "================================================"
    log "Robot Mode E2E Test Suite"
    log "================================================"
    log "DCG Binary: $DCG"
    log "Log File: $LOG_FILE"
    log "Project Root: $PROJECT_ROOT"
    log ""

    # Clear log file
    : > "$LOG_FILE"

    # Verify binary exists
    if [ ! -x "$DCG" ]; then
        log "ERROR: DCG binary not found or not executable: $DCG"
        log "Run 'cargo build --release' first"
        exit 2
    fi

    # Log version
    local version
    version=$("$DCG" --version 2>&1 || true)
    log "DCG Version: $version"
    log ""
}

#------------------------------------------------------------------------------
# Test Helpers
#------------------------------------------------------------------------------

run_test() {
    local name="$1"
    shift
    ((TESTS_RUN++))
    log "--- Test $TESTS_RUN: $name ---"
    if "$@"; then
        log_pass "$name"
        return 0
    else
        log_fail "$name"
        return 1
    fi
}

assert_eq() {
    local actual="$1"
    local expected="$2"
    local msg="${3:-Values should be equal}"
    if [ "$actual" = "$expected" ]; then
        return 0
    else
        log "  Expected: $expected"
        log "  Actual: $actual"
        return 1
    fi
}

assert_exit_code() {
    local actual="$1"
    local expected="$2"
    assert_eq "$actual" "$expected" "Exit code should be $expected"
}

assert_json_valid() {
    local json="$1"
    if echo "$json" | jq . > /dev/null 2>&1; then
        return 0
    else
        log "  Invalid JSON: $json"
        return 1
    fi
}

assert_no_ansi() {
    local text="$1"
    if echo "$text" | grep -q $'\x1b\['; then
        log "  Found ANSI escape codes in output"
        return 1
    fi
    return 0
}

#------------------------------------------------------------------------------
# Tests
#------------------------------------------------------------------------------

test_robot_flag_produces_json() {
    local result
    result=$("$DCG" --robot test "git status" 2>&1)
    assert_json_valid "$result"
}

test_allowed_command_exits_0() {
    "$DCG" --robot test "echo hello" > /dev/null 2>&1
    local exit_code=$?
    assert_exit_code "$exit_code" "0"
}

test_denied_command_exits_1() {
    "$DCG" --robot test "rm -rf /" > /dev/null 2>&1 || true
    local exit_code=$?
    assert_exit_code "$exit_code" "1"
}

test_no_ansi_in_stdout() {
    local stdout
    stdout=$("$DCG" --robot test "rm -rf /" 2>/dev/null || true)
    assert_no_ansi "$stdout"
}

test_no_ansi_in_stderr() {
    local stderr
    stderr=$("$DCG" --robot test "rm -rf /" 2>&1 >/dev/null || true)
    assert_no_ansi "$stderr"
}

test_stderr_is_silent() {
    local stderr
    stderr=$("$DCG" --robot test "rm -rf /" 2>&1 >/dev/null || true)
    if [ -n "$stderr" ]; then
        log "  Stderr should be empty, got: $stderr"
        return 1
    fi
    return 0
}

test_dcg_robot_env_produces_json() {
    local result
    result=$(DCG_ROBOT=1 "$DCG" test "git status" 2>&1)
    assert_json_valid "$result"
}

test_dcg_robot_env_denied_exits_1() {
    DCG_ROBOT=1 "$DCG" test "rm -rf /" > /dev/null 2>&1 || true
    local exit_code=$?
    assert_exit_code "$exit_code" "1"
}

test_json_has_decision_field() {
    local result
    result=$("$DCG" --robot test "rm -rf /" 2>/dev/null || true)
    local decision
    decision=$(echo "$result" | jq -r '.decision')
    assert_eq "$decision" "deny"
}

test_json_has_rule_id_field() {
    local result
    result=$("$DCG" --robot test "rm -rf /" 2>/dev/null || true)
    local rule_id
    rule_id=$(echo "$result" | jq -r '.rule_id')
    if [ "$rule_id" = "null" ] || [ -z "$rule_id" ]; then
        log "  Missing rule_id in JSON"
        return 1
    fi
    log "  rule_id: $rule_id"
    return 0
}

test_json_has_severity_field() {
    local result
    result=$("$DCG" --robot test "rm -rf /" 2>/dev/null || true)
    local severity
    severity=$(echo "$result" | jq -r '.severity')
    if [ "$severity" = "null" ] || [ -z "$severity" ]; then
        log "  Missing severity in JSON"
        return 1
    fi
    log "  severity: $severity"
    return 0
}

test_performance_under_100ms() {
    local start end latency_ms
    start=$(date +%s%N)
    "$DCG" --robot test "echo test" > /dev/null 2>&1
    end=$(date +%s%N)
    latency_ms=$(( (end - start) / 1000000 ))
    log "  Latency: ${latency_ms}ms"
    if [ "$latency_ms" -gt 200 ]; then
        log "  WARNING: Latency exceeds 200ms threshold"
        return 1
    fi
    return 0
}

test_explain_command_json() {
    local result
    result=$("$DCG" --robot explain "git reset --hard" 2>&1)
    assert_json_valid "$result"
}

test_packs_command_json() {
    local result
    result=$("$DCG" --robot packs 2>&1)
    assert_json_valid "$result"
}

test_multiple_commands_consistency() {
    local cmd1 cmd2 exit1 exit2
    cmd1=$("$DCG" --robot test "rm -rf /" 2>/dev/null || true)
    exit1=$?
    cmd2=$("$DCG" --robot test "rm -rf /" 2>/dev/null || true)
    exit2=$?

    assert_exit_code "$exit1" "1" || return 1
    assert_exit_code "$exit2" "1" || return 1

    # JSON structure should be consistent
    local dec1 dec2
    dec1=$(echo "$cmd1" | jq -r '.decision')
    dec2=$(echo "$cmd2" | jq -r '.decision')
    assert_eq "$dec1" "$dec2"
}

test_empty_command_handled() {
    "$DCG" --robot test "" > /dev/null 2>&1 || true
    local exit_code=$?
    # Should not crash - exit 0 (allow) or 4 (parse error) are acceptable
    if [ "$exit_code" -ne 0 ] && [ "$exit_code" -ne 4 ]; then
        log "  Unexpected exit code for empty command: $exit_code"
        return 1
    fi
    return 0
}

test_special_chars_handled() {
    # Commands with special characters should not crash
    "$DCG" --robot test 'echo "hello world" | grep hello' > /dev/null 2>&1 || true
    local exit_code=$?
    if [ "$exit_code" -ne 0 ] && [ "$exit_code" -ne 1 ]; then
        log "  Unexpected exit code: $exit_code"
        return 1
    fi
    return 0
}

