main() {
    setup

    # Core functionality tests
    run_test "Robot flag produces valid JSON" test_robot_flag_produces_json || true
    run_test "Allowed command exits 0" test_allowed_command_exits_0 || true
    run_test "Denied command exits 1" test_denied_command_exits_1 || true
    run_test "No ANSI in stdout" test_no_ansi_in_stdout || true
    run_test "No ANSI in stderr" test_no_ansi_in_stderr || true
    run_test "Stderr is silent" test_stderr_is_silent || true

    # Environment variable tests
    run_test "DCG_ROBOT env produces JSON" test_dcg_robot_env_produces_json || true
    run_test "DCG_ROBOT env denied exits 1" test_dcg_robot_env_denied_exits_1 || true

    # JSON structure tests
    run_test "JSON has decision field" test_json_has_decision_field || true
    run_test "JSON has rule_id field" test_json_has_rule_id_field || true
    run_test "JSON has severity field" test_json_has_severity_field || true

    # Performance tests
    run_test "Performance under 200ms" test_performance_under_100ms || true

    # Subcommand tests
    run_test "Explain command produces JSON" test_explain_command_json || true
    run_test "Packs command produces JSON" test_packs_command_json || true

    # Edge case tests
    run_test "Multiple commands consistency" test_multiple_commands_consistency || true
    run_test "Empty command handled" test_empty_command_handled || true
    run_test "Special chars handled" test_special_chars_handled || true

    # Summary
    log ""
    log "================================================"
    log "Test Summary"
    log "================================================"
    log "Total: $TESTS_RUN"
    log "Passed: $TESTS_PASSED"
